var e=JSON.parse(`[{"id":"L1_1","type":"dialog","speaker":"SPARROW_SL_REALEASE_NULL","text":{"KOREA":"<color=#ffd34c>못된 악당</color> 발견. 사격 개시. 사격 개시.","JPN":"<color=#ffd34c>悪党</color>発見。射撃開始。射撃開始。","ENG":"<color=#ffd34c>Evil villain</color> detected. Fire. Fire.","TWN":"發現<color=#ffd34c>可惡的壞蛋</color>，開始射擊，開始射擊。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPARROW_SL_REALEASE_NULL","face":"UNIT_TOUCH"},"R":null}},"sfx":"FX_CUTSCEN_DOOR_SF"},{"id":"L2_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"방해만 할 거면 저리 꺼져! 이 멍청한 고철 같으니라고!","JPN":"邪魔しかできないならとっとと失せろ！　このポンコツめ！","ENG":"Stop interfering with me and get lost! You stupid tin can!","TWN":"給我滾開！笨手笨腳的廢鐵！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L6_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"칫, 대체 어떻게 된 거야?","JPN":"ちっ、一体どういうことだ？","ENG":"Bah, what the hell is going on?","TWN":"哼，這到底是怎麼回事？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"어째서 능력을 써도 이까짓 드론 하나의 통제권조차 가져올 수 없는 거지?","JPN":"どうして能力を使ってるのにこんなカスドローンの\\n統制権すら奪えないんだ？","ENG":"I can't even take over a drone, no matter how hard I try.","TWN":"為什麼我連一個無人機都操控不了了？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"마치 내 능력이 뭔가에 가로막히는 느낌이야...... 이건 대체?","JPN":"まるで俺の能力が何かに阻まれている感覚だ……\\nこれはいったい？","ENG":"It's as if something is blocking me. But what?","TWN":"好像被某種東西擋住了一樣……這到底是？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음! 무슨 일인가?","JPN":"うむ！　どうした？","ENG":"Mm? What was that?","TWN":"嗯！怎麼了？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"방금 내 빛나는 장갑판을 손바닥으로 두드린 것 같은데?","JPN":"今、吾輩の輝く装甲板を手のひらで叩いたようだが？","ENG":"Did you just tap on my shining armor?","TWN":"你剛才好像用手拍了一下我閃亮的裝甲板？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응! 할아버지 어깨 위로 조그만 벌레가 기어 다니길래 내가 잡아서 던져 버렸어!","JPN":"うん！　おじいちゃん！　肩に小さな虫がいたから、\\n私が捕まえてぶん投げたのよ！","ENG":"Yup! I found a tiny crawly on your shoulder, so I squished it and threw it away!","TWN":"嗯！我看到爺爺的肩膀上有一條小蟲子，所以我把它扔到遠處了！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"벌레? 내 카메라에는 보이지 않았는데.","JPN":"虫？　吾輩のカメラには映らなかったが。","ENG":"A crawly? There was nothing on my camera.","TWN":"蟲子？我的攝像頭沒看到啊。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"어쩌면 이 타이탄은 볼 수 없는 걸 시그마는 볼 수 있는 걸지도 모르겠구나.","JPN":"もしかしたら、このタイタンには見えないものもシグマには\\n見えるのかもしれんな。","ENG":"Sigma, maybe you can see things that I can't.","TWN":"看來西格瑪能看到泰坦看不見的東西。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"앗!","JPN":"あっ！","ENG":"Oooh!","TWN":"啊！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"정말 그럴 수도 있겠네! 난 특별하니까!","JPN":"本当にそうかもしれない！　私は特別だからね！","ENG":"You may be right. I'm special!","TWN":"真的有可能喔！因為我很特別呀！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"엣헴! 그럼 이번엔 저쪽을 도와주러 가자! 할아버지!","JPN":"えっへん！　じゃあ、今度はあっちを助けて\\nあげようよ、おじいちゃん！","ENG":"Ahem! Now, let's go help them over there, Grandpa!","TWN":"咳咳！接下來去那邊幫忙吧！爺爺！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음! 알겠네! 속도를 높일 테니 잘 붙들고 있게나!","JPN":"うむ！　いいぞ！　速度を上げるからしっかり掴まるんだぞ！","ENG":"Mm, sure. I'm going to speed up. Hold on tight!","TWN":"嗯！好！抓緊，我要加速了！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"역시 저 꼬맹이가 내 능력을 방해하고 있는 건가!","JPN":"やはりあのチビが俺の能力を邪魔しているのか！","ENG":"I knew that little girl was messing with my power!","TWN":"果然是那個小鬼在妨礙我的能力！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"젠장...... 밖에서는 카운터, 안에서는 메카닉들이 날뛰고 있다니, 최악이군.","JPN":"ちくしょう……外はカウンター、中はメカニックが暴れてる\\nなんて、最悪な状況だな。","ENG":"Drat, I'm dealing with Counters on the outside and mechs on the inside. This is terrible.","TWN":"該死……外有制裁者，內有裝甲部隊，真是糟透了。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"하지만 반대로 생각하면 저 꼬맹이만 제거하면 모든 것이 다시 내 손에 들어온다는 의미가 되는군.","JPN":"でも逆手に取って、あのチビさえ消しちまえばすべてが\\n再び俺の手に落ちるってことだな。","ENG":"But on the bright side, I can have all these if I can just get rid of that kid.","TWN":"不過，只要我幹掉那個小鬼，我就能再次奪回所有控制權。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"좋아...... 위험하긴 하지만 해볼 수 밖에.","JPN":"よし……危険ではあるが、やるっきゃない。","ENG":"Alright, this is going to be dangerous, but I have no other choice.","TWN":"好……只能冒險試一試了。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"어이! 들리나?","JPN":"おい！　聞こえるか？","ENG":"Hey! Can you hear me?","TWN":"喂！能聽到嗎？"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PIRATE_FOX_NULL_NULL","text":{"KOREA":"예, 대장!","JPN":"はい、隊長！","ENG":"Yes, Captain!","TWN":"是，隊長！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"가장 최근에 나와 <color=#ffd34c>박사</color>가 함께 개조한 <color=#ffd34c>그걸</color> 꺼내와라.","JPN":"最近俺と<color=#ffd34c>博士</color>が共同改造した<color=#ffd34c>アレ</color>を\\n出してこい。","ENG":"Bring me the <color=#ffd34c>thing</color> that the <color=#ffd34c>Doctor</color> and I modified together.","TWN":"去把<color=#ffd34c>那個東西</color>拿過來，就是我和<color=#ffd34c>博士</color>最近改造的那個。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PIRATE_FOX_NULL_NULL","text":{"KOREA":"예? 하지만 <color=#ffd34c>그건</color> 아직 AI가 탑재되지 않아서 수동으로 조작해야 할 텐데요.","JPN":"え？　<color=#ffd34c>アレ</color>はまだAIが搭載されていないので、\\n手動でしか操作できませんが……","ENG":"Pardon? But <color=#ffd34c>it</color>'s not embedded with AI yet. For now, it can only be controlled manually.","TWN":"啊？但是<color=#ffd34c>那個東西</color>還沒有搭載AI，只能手動操作。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"바로 그거다. 그렇기 때문에 그 기계라면 반란을 일으킬 걱정도 없지.","JPN":"だからいいんだ。手動で動かすからこそ、途中で\\n裏切られる心配もないだろう。","ENG":"That's precisely my point. I don't have to worry about it turning against me.","TWN":"沒錯，正是因為這樣才不用擔心它會叛變。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"STINGER_FOX_BOSS_NULL","text":{"KOREA":"서둘러! 그걸 이용해서 저 꼬맹이만 처리하면 나머지 문제는 쉽게 해결된다.","JPN":"急げ！　それを使ってあのチビさえ片づければ\\n他は余裕だ。","ENG":"Hurry! Once we take care of that girl with it, everything else will fix itself.","TWN":"快點！只要處理掉那個小鬼，剩下的問題就迎刃而解了。"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PIRATE_FOX_NULL_NULL","text":{"KOREA":"......알겠습니다!","JPN":"……わかりました！","ENG":"Yes, ma'am!","TWN":"……明白！"},"stage":{"bg":"HANGAR","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STINGER_FOX_BOSS_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"}]`);export{e as default};